    // =========================================================================
    // Helper builders
    // =========================================================================

    /** Builds a Cost with a single colour requirement. */
    private Cost cost(GemColor color, int amount) {
        Map<GemColor, Integer> map = new EnumMap<>(GemColor.class);
        map.put(color, amount);
        return new Cost(map);
    }

    /**
     * Builds a minimal card (costs WHITE:1) with the given bonus colour.
     * Used to give players purchased card bonuses via addCard().
     */
    private Card minimalCard(GemColor bonus) {
        return new Card(1, 0, bonus, cost(GemColor.WHITE, 1));
    }

    private Noble noble(int id, Map<GemColor, Integer> requirements) {
        return new Noble(id, "Noble-" + id, requirements);
    }

    /** Builds a requirements map from colour-amount pairs. */
    private Map<GemColor, Integer> req(Object... pairs) {
        Map<GemColor, Integer> map = new EnumMap<>(GemColor.class);
        for (int i = 0; i < pairs.length; i += 2) {
            map.put((GemColor) pairs[i], (Integer) pairs[i + 1]);
        }
        return map;
    }

    private Player playerWithBonuses(GemColor color, int count) {
        Player p = new Player("BonusPlayer", 1);
        for (int i = 0; i < count; i++) {
            p.addCard(minimalCard(color));
        }
        return p;
    }

    // =========================================================================
    // FIX #1: Property-based card matching instead of reference equality.
    //
    // Card likely doesn't override equals(), so List.contains() uses ==.
    // After CardMarket shuffles, the original object may not be in the visible
    // slots — but a copy with identical properties is. This helper compares
    // by level, points, bonus, and per-colour cost.
    // =========================================================================

    /**
     * Returns true if the list contains at least one Card whose level, points,
     * bonus colour, and per-colour cost all match the target card.
     */
    private boolean containsMatchingCard(List<Card> cards, Card target) {
        for (Card c : cards) {
            if (c.getLevel() == target.getLevel()
                && c.getPoints() == target.getPoints()
                && c.getBonus() == target.getBonus()
                && sameCost(c.getCost(), target.getCost())) {
                return true;
            }
        }
        return false;
    }

    /** Returns true if two Cost objects require the same amount of each colour. */
    private boolean sameCost(Cost a, Cost b) {
        for (GemColor color : GemColor.values()) {
            if (color == GemColor.GOLD) continue;
            if (a.getRequired(color) != b.getRequired(color)) return false;
        }
        return true;
    }

    /**
     * Counts how many cards in the list match the target by properties.
     * Useful for asserting "at least N affordable cards of this type".
     */
    private long countMatchingCards(List<Card> cards, Card target) {
        long count = 0;
        for (Card c : cards) {
            if (c.getLevel() == target.getLevel()
                && c.getPoints() == target.getPoints()
                && c.getBonus() == target.getBonus()
                && sameCost(c.getCost(), target.getCost())) {
                count++;
            }
        }
        return count;
    }

    // =========================================================================
    // FIX #2: Market builders that avoid filler-card pollution.
    //
    // The original buildState padded empty tiers with cards costing WHITE:1
    // (via padToTwenty). For findAllAffordableCards tests this was fine because
    // those filler cards are cheap but irrelevant. For discountUtility, however,
    // the WHITE:1 filler (or all-colour filler in emptyState) polluted the
    // matching ratio.
    //
    // Solution:
    //   - For findAllAffordableCards: use buildStateForAffordability which pads
    //     with un-affordable filler (costs 7 of every colour).
    //   - For discountUtility: use buildStateForDiscount which pads with
    //     "neutral" filler whose cost matches the *same* colour as the tier's
    //     real card, so the ratio within each tier stays consistent. Empty tiers
    //     use filler that costs only BLACK:1 (a colour unlikely to be the bonus
    //     being tested with cheapCard/GREEN).
    // =========================================================================

    /**
     * Builds an un-affordable filler card (costs 7 of every non-GOLD colour).
     * No player in our test suite can afford this, and no reasonable bonus
     * colour query will accidentally match all 5 colours uniformly.
     */
    private Card unaffordableFiller() {
        Map<GemColor, Integer> map = new EnumMap<>(GemColor.class);
        for (GemColor c : GemColor.values()) {
            if (c != GemColor.GOLD) map.put(c, 7);
        }
        return new Card(1, 0, GemColor.WHITE, new Cost(map));
    }

    /**
     * Pads a list to 20 by repeating the first card (or a filler if empty).
     * The filler parameter controls what goes in when the list is empty.
     */
    private List<Card> padToTwenty(List<Card> cards, Card filler) {
        List<Card> padded = new ArrayList<>(cards);
        Card template = cards.isEmpty() ? filler : cards.get(0);
        while (padded.size() < 20) {
            padded.add(new Card(
                template.getLevel(),
                template.getPoints(),
                template.getBonus(),
                template.getCost()
            ));
        }
        return padded;
    }

    // --- Affordability builders ---

    /**
     * Builds a GameState for findAllAffordableCards tests.
     * Empty tiers are padded with un-affordable filler so they never produce
     * false positives.
     */
    private GameState stateWithTier1(Card... cards) {
        return buildStateForAffordability(
            new ArrayList<>(List.of(cards)),
            Collections.emptyList(),
            Collections.emptyList()
        );
    }

    private GameState stateWithAllTiers(List<Card> t1, List<Card> t2, List<Card> t3) {
        return buildStateForAffordability(
            new ArrayList<>(t1),
            new ArrayList<>(t2),
            new ArrayList<>(t3)
        );
    }

    private GameState buildStateForAffordability(List<Card> t1, List<Card> t2, List<Card> t3) {
        Card filler = unaffordableFiller();
        CardMarket market = new CardMarket(
            padToTwenty(t1, filler),
            padToTwenty(t2, filler),
            padToTwenty(t3, filler)
        );
        Player dummy = new Player("Dummy", 1);
        return new GameState(
            List.of(dummy), market, fullBank, Collections.emptyList(), 15
        );
    }

    /**
     * A market where every card is un-affordable — used as "empty" for
     * findAllAffordableCards tests. Because every filler costs 7 of all
     * colours, no test player can afford anything.
     */
    private GameState emptyAffordabilityState() {
        return buildStateForAffordability(
            Collections.emptyList(),
            Collections.emptyList(),
            Collections.emptyList()
        );
    }

    // --- Discount utility builders ---

    /**
     * Builds a GameState for discountUtility tests.
     *
     * Each tier is padded by repeating its own real card so the visible/deck
     * split after shuffle doesn't change the ratio.  Empty tiers are filled
     * with "neutral" filler that costs only BLACK:1 — this avoids accidentally
     * matching GREEN (cheapCard's bonus) or other colours under test.
     */
    private GameState buildStateForDiscount(List<Card> t1, List<Card> t2, List<Card> t3) {
        // Neutral filler: costs only BLACK:1, bonus RED.
        // Will NOT match GREEN (cheapCard's bonus) in any discountUtility test.
        Card neutralFiller = new Card(1, 0, GemColor.RED, cost(GemColor.BLACK, 1));
        CardMarket market = new CardMarket(
            padToTwenty(t1, neutralFiller),
            padToTwenty(t2, neutralFiller),
            padToTwenty(t3, neutralFiller)
        );
        Player dummy = new Player("Dummy", 1);
        return new GameState(
            List.of(dummy), market, fullBank, Collections.emptyList(), 15
        );
    }

    /**
     * A market where no visible card's cost includes GREEN (cheapCard's bonus).
     * All filler costs only BLACK:1, so discountUtility returns 0.0 for a
     * GREEN-bonus card.
     */
    private GameState emptyDiscountState() {
        return buildStateForDiscount(
            Collections.emptyList(),
            Collections.emptyList(),
            Collections.emptyList()
        );
    }

