    @Nested
    @DisplayName("findAllAffordableCards")
    class FindAllAffordableCardsTests {

        @Test
        @DisplayName("Returns empty list when market and reserved hand are both empty")
        void emptyMarketAndReserved_returnsEmptyList() {
            List<Card> result = CardEvaluator.findAllAffordableCards(
                emptyAffordabilityState(), brokePlayer);
            assertTrue(result.isEmpty());
        }

        @Test
        @DisplayName("Returns card when player has exactly the right single gem")
        void singleGem_cardIsAffordable() {
            Card singleGemCard = new Card(1, 0, GemColor.RED, cost(GemColor.WHITE, 1));
            Player p = new Player("SingleGem", 1);
            p.addGems(new GemCollection().add(GemColor.WHITE, 1));
            GameState state = stateWithTier1(singleGemCard);
            List<Card> result = CardEvaluator.findAllAffordableCards(state, p);
            assertTrue(containsMatchingCard(result, singleGemCard),
                "Result should contain a card matching singleGemCard by properties");
        }

        @Test
        @DisplayName("Does not return a card the player cannot afford")
        void cannotAffordExpensiveCard() {
            GameState state = stateWithTier1(expensiveCard);
            List<Card> result = CardEvaluator.findAllAffordableCards(state, brokePlayer);
            assertFalse(containsMatchingCard(result, expensiveCard),
                "Broke player should not be able to afford the expensive card");
        }

        @Test
        @DisplayName("Returns card when player has exactly enough gems")
        void exactGems_cardIsAffordable() {
            GameState state = stateWithTier1(cheapCard);
            List<Card> result = CardEvaluator.findAllAffordableCards(state, richPlayer);
            assertTrue(containsMatchingCard(result, cheapCard),
                "Result should contain a card matching cheapCard by properties");
        }

        @Test
        @DisplayName("Returns card when player has more than enough gems")
        void surplusGems_cardIsAffordable() {
            Player wealthy = new Player("Wealthy", 1);
            wealthy.addGems(new GemCollection()
                .add(GemColor.RED,  10)
                .add(GemColor.BLUE, 10));
            GameState state = stateWithTier1(cheapCard);
            List<Card> result = CardEvaluator.findAllAffordableCards(state, wealthy);
            assertTrue(containsMatchingCard(result, cheapCard),
                "Wealthy player should be able to afford cheapCard");
        }

        @Test
        @DisplayName("Scans all three tiers and returns affordable cards from each")
        void returnsCardsFromAllThreeTiers() {
            Map<GemColor, Integer> sameCost = new EnumMap<>(GemColor.class);
            sameCost.put(GemColor.RED,  2);
            sameCost.put(GemColor.BLUE, 1);
            Card tier1Card = new Card(1, 1, GemColor.GREEN, new Cost(sameCost));
            Card tier2Card = new Card(2, 1, GemColor.WHITE, new Cost(sameCost));
            Card tier3Card = new Card(3, 1, GemColor.BLACK, new Cost(sameCost));
            GameState state = stateWithAllTiers(
                List.of(tier1Card),
                List.of(tier2Card),
                List.of(tier3Card)
            );
            List<Card> result = CardEvaluator.findAllAffordableCards(state, richPlayer);
            // Each card has a unique level, so containsMatchingCard distinguishes them
            assertTrue(containsMatchingCard(result, tier1Card), "Should find tier 1 card");
            assertTrue(containsMatchingCard(result, tier2Card), "Should find tier 2 card");
            assertTrue(containsMatchingCard(result, tier3Card), "Should find tier 3 card");
        }

        @Test
        @DisplayName("Includes affordable card from reserved hand when market is empty")
        void affordableReservedCard_includedInResult() {
            richPlayer.addReservedCard(cheapCard);
            List<Card> result = CardEvaluator.findAllAffordableCards(
                emptyAffordabilityState(), richPlayer);
            // Reserved cards are the actual object (no shuffle), so contains() works
            assertTrue(result.contains(cheapCard));
        }

        @Test
        @DisplayName("Does not include unaffordable card from reserved hand")
        void unaffordableReservedCard_notIncluded() {
            brokePlayer.addReservedCard(expensiveCard);
            List<Card> result = CardEvaluator.findAllAffordableCards(
                emptyAffordabilityState(), brokePlayer);
            assertFalse(result.contains(expensiveCard));
        }

        @Test
        @DisplayName("Bonuses from purchased cards count toward affording a reserved card")
        void bonusesReduceCost_makingReservedCardAffordable() {
            Player p = playerWithBonuses(GemColor.RED, 4);
            p.addGems(new GemCollection()
                .add(GemColor.BLUE,  3)
                .add(GemColor.GREEN, 2));
            p.addReservedCard(expensiveCard);
            List<Card> result = CardEvaluator.findAllAffordableCards(
                emptyAffordabilityState(), p);
            assertTrue(result.contains(expensiveCard));
        }

        @Test
        @DisplayName("GOLD gems cover any colour deficit making the card affordable")
        void goldGems_actAsWild() {
            Player goldPlayer = new Player("Gold", 1);
            goldPlayer.addGems(new GemCollection().add(GemColor.GOLD, 3));
            GameState state = stateWithTier1(cheapCard);
            List<Card> result = CardEvaluator.findAllAffordableCards(state, goldPlayer);
            assertTrue(containsMatchingCard(result, cheapCard),
                "GOLD gems should cover the deficit, making cheapCard affordable");
        }

        @Test
        @DisplayName("Result contains no null entries")
        void resultContainsNoNullEntries() {
            Map<GemColor, Integer> sameCost = new EnumMap<>(GemColor.class);
            sameCost.put(GemColor.RED,  2);
            sameCost.put(GemColor.BLUE, 1);
            Card card1 = new Card(1, 1, GemColor.GREEN, new Cost(sameCost));
            Card card2 = new Card(1, 2, GemColor.WHITE, new Cost(sameCost));
            GameState state = stateWithTier1(card1, card2);
            List<Card> result = CardEvaluator.findAllAffordableCards(state, richPlayer);
            result.forEach(card ->
                assertNotNull(card, "Result list must not contain null entries"));
        }

        @Test
        @DisplayName("Player with no gems and no bonuses cannot afford any card with a cost")
        void brokePlayerCannotAffordCardWithCost() {
            Card minCard = new Card(1, 0, GemColor.BLUE, cost(GemColor.RED, 1));
            GameState state = stateWithTier1(minCard);
            List<Card> result = CardEvaluator.findAllAffordableCards(state, brokePlayer);
            assertFalse(containsMatchingCard(result, minCard),
                "Broke player should not afford any card with a cost");
        }
    }

