    @Nested
    @DisplayName("calculateDeficit")
    class CalculateDeficitTests {

        @Test
        @DisplayName("Returns empty map when player gems exactly cover the card cost")
        void exactGems_noDeficit() {
            Map<GemColor, Integer> deficit = CardEvaluator.calculateDeficit(richPlayer, cheapCard);
            assertTrue(deficit.isEmpty());
        }

        @Test
        @DisplayName("Returns full cost as deficit when player has zero gems")
        void brokePlayer_fullDeficit() {
            Map<GemColor, Integer> deficit = CardEvaluator.calculateDeficit(brokePlayer, cheapCard);
            assertEquals(2, deficit.get(GemColor.RED));
            assertEquals(1, deficit.get(GemColor.BLUE));
        }

        @Test
        @DisplayName("Returns empty map when player has more than enough gems")
        void surplusGems_noDeficit() {
            Player wealthy = new Player("Wealthy", 1);
            wealthy.addGems(new GemCollection()
                .add(GemColor.RED,  10)
                .add(GemColor.BLUE, 10));
            assertTrue(CardEvaluator.calculateDeficit(wealthy, cheapCard).isEmpty());
        }

        @Test
        @DisplayName("Returns partial deficit when player covers some colours but not all")
        void partialGems_partialDeficit() {
            Player p = new Player("Partial", 1);
            p.addGems(new GemCollection().add(GemColor.RED, 1));
            Map<GemColor, Integer> deficit = CardEvaluator.calculateDeficit(p, cheapCard);
            assertEquals(1, deficit.get(GemColor.RED));
            assertEquals(1, deficit.get(GemColor.BLUE));
        }

        @Test
        @DisplayName("Purchased card bonuses from addCard() reduce the deficit")
        void purchasedCardBonuses_reduceDeficit() {
            Player p = playerWithBonuses(GemColor.RED, 1);
            p.addGems(new GemCollection().add(GemColor.RED, 1));
            Map<GemColor, Integer> deficit = CardEvaluator.calculateDeficit(p, cheapCard);
            assertFalse(deficit.containsKey(GemColor.RED));
            assertEquals(1, deficit.get(GemColor.BLUE));
        }

        @Test
        @DisplayName("Bonus that exceeds the cost does not produce a negative deficit entry")
        void bonusExceedsCost_noNegativeDeficit() {
            Player p = playerWithBonuses(GemColor.RED, 5);
            Map<GemColor, Integer> deficit = CardEvaluator.calculateDeficit(p, cheapCard);
            deficit.values().forEach(v ->
                assertTrue(v > 0, "All deficit values must be positive"));
            assertFalse(deficit.containsKey(GemColor.RED));
        }

        @Test
        @DisplayName("GOLD gems held by player do not reduce per-colour deficit entries")
        void goldGems_notCountedInDeficit() {
            Player p = new Player("Gold", 1);
            p.addGems(new GemCollection().add(GemColor.GOLD, 5));
            Map<GemColor, Integer> deficit = CardEvaluator.calculateDeficit(p, cheapCard);
            assertEquals(2, deficit.get(GemColor.RED));
            assertEquals(1, deficit.get(GemColor.BLUE));
        }

        @Test
        @DisplayName("GOLD is never a key in the returned deficit map")
        void goldNeverAppearsAsDeficitKey() {
            Map<GemColor, Integer> deficit = CardEvaluator.calculateDeficit(
                brokePlayer, expensiveCard);
            assertFalse(deficit.containsKey(GemColor.GOLD));
        }

        @Test
        @DisplayName("Only colours with a positive deficit appear as keys")
        void onlyPositiveDeficitsAppearAsKeys() {
            Player p = new Player("Partial", 1);
            p.addGems(new GemCollection().add(GemColor.BLUE, 2));
            Map<GemColor, Integer> deficit = CardEvaluator.calculateDeficit(p, cheapCard);
            assertTrue(deficit.containsKey(GemColor.RED));
            assertFalse(deficit.containsKey(GemColor.BLUE));
        }

        @Test
        @DisplayName("Colours not in the card cost never appear as deficit keys")
        void colourNotInCost_neverInDeficit() {
            Map<GemColor, Integer> deficit = CardEvaluator.calculateDeficit(
                brokePlayer, cheapCard);
            assertFalse(deficit.containsKey(GemColor.GREEN));
            assertFalse(deficit.containsKey(GemColor.WHITE));
            assertFalse(deficit.containsKey(GemColor.BLACK));
        }

        @Test
        @DisplayName("Boundary: exact gem match produces empty deficit map")
        void exactMatchBoundary_emptyDeficit() {
            assertTrue(CardEvaluator.calculateDeficit(richPlayer, cheapCard).isEmpty());
        }
    }

